def doc_to_text(doc: dict) -> str:
    contexts = doc.get("_retrieval_contexts", [])
    return _build_prompt(doc, contexts)

lcb_v4mv2_retrieval_agg4.process_results:
def process_results(doc: dict, results: List[str]) -> Dict:
    raw = results[0] if results else ""
    response = raw[0] if isinstance(raw, list) else raw
    if not isinstance(response, str):
        response = ""
    code = _extract_code(response)

    if code is None:
        passed = False
    else:
        passed = _evaluate_code(code, doc)

    return {
        "exact_match": int(passed),
        "pass_at_1": int(passed),
    }
